"use client";

import { useMemo, useState } from "react";
import { Check, ChevronLeft, ChevronRight } from "lucide-react";
import PageHero from "@/components/PageHero";
import SectionReveal from "@/components/SectionReveal";
import { SITE } from "@/lib/constants";
import styles from "./page.module.css";

type StepKey = "patient" | "route" | "transport" | "contact";

type FormState = {
  patientName: string;
  patientWeight: string;
  requiresOxygen: "yes" | "no";
  mobilityType: "ambulatory" | "wheelchair" | "stretcher";
  pickupAddress: string;
  pickupFacility: string;
  pickupRoom: string;
  pickupDate: string;
  pickupTime: string;
  dropoffAddress: string;
  dropoffFacility: string;
  appointmentTime: string;
  tripType: "one-way" | "return";
  driverWait: "yes" | "no";
  escortCount: number;
  needsWheelchair: boolean;
  needsStretcher: boolean;
  needsOxygen: boolean;
  needsTwoAttendants: boolean;
  specialInstructions: string;
  equipmentRequired: string;
  mobilityDetails: string;
  payer: "patient" | "family" | "hospital" | "care-home";
  paymentMethod: "credit-card" | "cash" | "e-transfer" | "net-30";
  contactName: string;
  contactPhone: string;
  contactEmail: string;
};

const steps: { id: StepKey; label: string }[] = [
  { id: "patient", label: "Patient Info" },
  { id: "route", label: "Pickup and Destination" },
  { id: "transport", label: "Transport Details" },
  { id: "contact", label: "Contact and Billing" },
];

const initialState: FormState = {
  patientName: "",
  patientWeight: "",
  requiresOxygen: "no",
  mobilityType: "ambulatory",
  pickupAddress: "",
  pickupFacility: "",
  pickupRoom: "",
  pickupDate: "",
  pickupTime: "",
  dropoffAddress: "",
  dropoffFacility: "",
  appointmentTime: "",
  tripType: "one-way",
  driverWait: "no",
  escortCount: 0,
  needsWheelchair: false,
  needsStretcher: false,
  needsOxygen: false,
  needsTwoAttendants: false,
  specialInstructions: "",
  equipmentRequired: "",
  mobilityDetails: "",
  payer: "patient",
  paymentMethod: "credit-card",
  contactName: "",
  contactPhone: "",
  contactEmail: "",
};

export default function BookPage() {
  const [form, setForm] = useState<FormState>(initialState);
  const [stepIndex, setStepIndex] = useState(0);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [submitting, setSubmitting] = useState(false);
  const [status, setStatus] = useState<"idle" | "success" | "error">("idle");

  const progress = useMemo(
    () => `${((stepIndex + 1) / steps.length) * 100}%`,
    [stepIndex]
  );

  function setField<K extends keyof FormState>(key: K, value: FormState[K]) {
    setForm((prev) => ({ ...prev, [key]: value }));
  }

  function validateCurrentStep() {
    const nextErrors: Record<string, string> = {};
    const step = steps[stepIndex].id;

    if (step === "patient") {
      if (!form.patientName.trim()) nextErrors.patientName = "Patient name is required";
      if (!form.patientWeight.trim()) nextErrors.patientWeight = "Patient weight is required";
    }

    if (step === "route") {
      if (!form.pickupAddress.trim()) nextErrors.pickupAddress = "Pickup address is required";
      if (!form.pickupDate) nextErrors.pickupDate = "Pickup date is required";
      if (!form.pickupTime) nextErrors.pickupTime = "Pickup time is required";
      if (!form.dropoffAddress.trim()) nextErrors.dropoffAddress = "Destination address is required";
    }

    if (step === "contact") {
      if (!form.contactName.trim()) nextErrors.contactName = "Contact name is required";
      if (!form.contactPhone.trim()) nextErrors.contactPhone = "Phone is required";
      if (!form.contactEmail.trim()) nextErrors.contactEmail = "Email is required";
    }

    setErrors(nextErrors);
    return Object.keys(nextErrors).length === 0;
  }

  async function submitBooking() {
    setSubmitting(true);
    setStatus("idle");

    try {
      const payload = {
        ...form,
        escortCount: String(form.escortCount),
        website: "",
      };

      const response = await fetch("/api/booking", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        throw new Error("Submit failed");
      }

      setStatus("success");
      setForm(initialState);
      setStepIndex(0);
      setErrors({});
      window.scrollTo({ top: 0, behavior: "smooth" });
    } catch {
      setStatus("error");
    } finally {
      setSubmitting(false);
    }
  }

  function nextStep() {
    if (!validateCurrentStep()) return;
    setStepIndex((prev) => Math.min(prev + 1, steps.length - 1));
  }

  function previousStep() {
    setStepIndex((prev) => Math.max(prev - 1, 0));
  }

  return (
    <>
      <PageHero
        title="Book a Transport"
        subtitle="Complete the form below. A dispatcher will confirm your booking."
        breadcrumb="Book"
      />

      <section className="section">
        <div className="container">
          <SectionReveal className={`card ${styles.wizardCard}`}>
            <div className={styles.progressHeader}>
              <div className={styles.stepLabels}>
                {steps.map((step, index) => (
                  <div key={step.id} className={styles.stepItem} data-active={index <= stepIndex}>
                    <span>{index < stepIndex ? <Check size={14} /> : index + 1}</span>
                    <p>{step.label}</p>
                  </div>
                ))}
              </div>
              <div className={styles.progressBar}>
                <span style={{ width: progress }} />
              </div>
            </div>

            {status === "success" && (
              <p className={styles.success}>
                Booking request submitted. Dispatch will contact you shortly.
              </p>
            )}
            {status === "error" && (
              <p className={styles.error}>
                We could not submit the request. Call dispatch at {SITE.phoneDisplay}.
              </p>
            )}

            <div className={styles.stepPanel}>
              {steps[stepIndex].id === "patient" && (
                <div className={styles.formGrid}>
                  <label>
                    Patient name
                    <input
                      value={form.patientName}
                      onChange={(event) => setField("patientName", event.target.value)}
                    />
                    {errors.patientName && <span className={styles.fieldError}>{errors.patientName}</span>}
                  </label>

                  <label>
                    Patient weight (lbs)
                    <input
                      type="number"
                      value={form.patientWeight}
                      onChange={(event) => setField("patientWeight", event.target.value)}
                    />
                    {errors.patientWeight && <span className={styles.fieldError}>{errors.patientWeight}</span>}
                  </label>

                  <div>
                    <span className={styles.groupLabel}>Requires oxygen</span>
                    <div className={styles.toggleRow}>
                      {(["no", "yes"] as const).map((value) => (
                        <button
                          key={value}
                          type="button"
                          className={styles.toggleButton}
                          data-active={form.requiresOxygen === value}
                          onClick={() => setField("requiresOxygen", value)}
                        >
                          {value === "yes" ? "Yes" : "No"}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div>
                    <span className={styles.groupLabel}>Mobility type</span>
                    <div className={styles.optionGrid}>
                      {([
                        ["ambulatory", "Ambulatory"],
                        ["wheelchair", "Wheelchair"],
                        ["stretcher", "Stretcher"],
                      ] as const).map(([value, label]) => (
                        <button
                          key={value}
                          type="button"
                          className={styles.optionCard}
                          data-active={form.mobilityType === value}
                          onClick={() => setField("mobilityType", value)}
                        >
                          {label}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}

              {steps[stepIndex].id === "route" && (
                <div className={styles.formGrid}>
                  <label>
                    Pickup address
                    <input
                      autoComplete="street-address"
                      placeholder="Start typing pickup address"
                      value={form.pickupAddress}
                      onChange={(event) => setField("pickupAddress", event.target.value)}
                    />
                    {errors.pickupAddress && <span className={styles.fieldError}>{errors.pickupAddress}</span>}
                  </label>

                  <label>
                    Facility name (if applicable)
                    <input
                      value={form.pickupFacility}
                      onChange={(event) => setField("pickupFacility", event.target.value)}
                    />
                  </label>

                  <label>
                    Room number
                    <input
                      value={form.pickupRoom}
                      onChange={(event) => setField("pickupRoom", event.target.value)}
                    />
                  </label>

                  <label>
                    Pickup date
                    <input
                      type="date"
                      value={form.pickupDate}
                      onChange={(event) => setField("pickupDate", event.target.value)}
                    />
                    {errors.pickupDate && <span className={styles.fieldError}>{errors.pickupDate}</span>}
                  </label>

                  <label>
                    Pickup time
                    <input
                      type="time"
                      value={form.pickupTime}
                      onChange={(event) => setField("pickupTime", event.target.value)}
                    />
                    {errors.pickupTime && <span className={styles.fieldError}>{errors.pickupTime}</span>}
                  </label>

                  <label>
                    Drop-off address
                    <input
                      autoComplete="street-address"
                      placeholder="Start typing destination"
                      value={form.dropoffAddress}
                      onChange={(event) => setField("dropoffAddress", event.target.value)}
                    />
                    {errors.dropoffAddress && <span className={styles.fieldError}>{errors.dropoffAddress}</span>}
                  </label>

                  <label>
                    Destination facility name
                    <input
                      value={form.dropoffFacility}
                      onChange={(event) => setField("dropoffFacility", event.target.value)}
                    />
                  </label>

                  <label>
                    Appointment time
                    <input
                      type="time"
                      value={form.appointmentTime}
                      onChange={(event) => setField("appointmentTime", event.target.value)}
                    />
                  </label>
                </div>
              )}

              {steps[stepIndex].id === "transport" && (
                <div className={styles.formGrid}>
                  <div>
                    <span className={styles.groupLabel}>Trip type</span>
                    <div className={styles.optionGrid}>
                      {([
                        ["one-way", "One Way"],
                        ["return", "Return Trip"],
                      ] as const).map(([value, label]) => (
                        <button
                          key={value}
                          type="button"
                          className={styles.optionCard}
                          data-active={form.tripType === value}
                          onClick={() => setField("tripType", value)}
                        >
                          {label}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div>
                    <span className={styles.groupLabel}>Will the driver wait?</span>
                    <div className={styles.toggleRow}>
                      {(["no", "yes"] as const).map((value) => (
                        <button
                          key={value}
                          type="button"
                          className={styles.toggleButton}
                          data-active={form.driverWait === value}
                          onClick={() => setField("driverWait", value)}
                          disabled={form.tripType === "one-way"}
                        >
                          {value === "yes" ? "Yes" : "No"}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div>
                    <span className={styles.groupLabel}>Number of escorts</span>
                    <div className={styles.stepper}>
                      <button
                        type="button"
                        onClick={() => setField("escortCount", Math.max(0, form.escortCount - 1))}
                      >
                        -
                      </button>
                      <span>{form.escortCount}</span>
                      <button
                        type="button"
                        onClick={() => setField("escortCount", Math.min(3, form.escortCount + 1))}
                      >
                        +
                      </button>
                    </div>
                  </div>

                  <div>
                    <span className={styles.groupLabel}>Medical assistance</span>
                    <div className={styles.checkGrid}>
                      {([
                        ["needsWheelchair", "Wheelchair Assistance"],
                        ["needsStretcher", "Stretcher Setup"],
                        ["needsOxygen", "Oxygen Required"],
                        ["needsTwoAttendants", "Two Attendants"],
                      ] as const).map(([key, label]) => (
                        <label key={key} className={styles.checkItem}>
                          <input
                            type="checkbox"
                            checked={form[key]}
                            onChange={(event) => setField(key, event.target.checked)}
                          />
                          {label}
                        </label>
                      ))}
                    </div>
                  </div>

                  <label>
                    Special instructions
                    <textarea
                      rows={4}
                      value={form.specialInstructions}
                      onChange={(event) => setField("specialInstructions", event.target.value)}
                    />
                  </label>

                  <label>
                    Equipment required
                    <input
                      value={form.equipmentRequired}
                      onChange={(event) => setField("equipmentRequired", event.target.value)}
                    />
                  </label>

                  <label>
                    Mobility assistance details
                    <input
                      value={form.mobilityDetails}
                      onChange={(event) => setField("mobilityDetails", event.target.value)}
                    />
                  </label>
                </div>
              )}

              {steps[stepIndex].id === "contact" && (
                <div className={styles.formGrid}>
                  <label>
                    Contact name
                    <input
                      value={form.contactName}
                      onChange={(event) => setField("contactName", event.target.value)}
                    />
                    {errors.contactName && <span className={styles.fieldError}>{errors.contactName}</span>}
                  </label>

                  <label>
                    Contact phone
                    <input
                      type="tel"
                      value={form.contactPhone}
                      onChange={(event) => setField("contactPhone", event.target.value)}
                    />
                    {errors.contactPhone && <span className={styles.fieldError}>{errors.contactPhone}</span>}
                  </label>

                  <label>
                    Contact email
                    <input
                      type="email"
                      value={form.contactEmail}
                      onChange={(event) => setField("contactEmail", event.target.value)}
                    />
                    {errors.contactEmail && <span className={styles.fieldError}>{errors.contactEmail}</span>}
                  </label>

                  <div>
                    <span className={styles.groupLabel}>Who is paying?</span>
                    <div className={styles.optionGrid}>
                      {([
                        ["patient", "Patient"],
                        ["family", "Family"],
                        ["hospital", "Hospital"],
                        ["care-home", "Care Home"],
                      ] as const).map(([value, label]) => (
                        <button
                          key={value}
                          type="button"
                          className={styles.optionCard}
                          data-active={form.payer === value}
                          onClick={() => setField("payer", value)}
                        >
                          {label}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div>
                    <span className={styles.groupLabel}>Payment method</span>
                    <div className={styles.optionGrid}>
                      {([
                        ["credit-card", "Credit Card"],
                        ["cash", "Cash"],
                        ["e-transfer", "E-Transfer"],
                        ["net-30", "Net 30"],
                      ] as const).map(([value, label]) => (
                        <button
                          key={value}
                          type="button"
                          className={styles.optionCard}
                          data-active={form.paymentMethod === value}
                          onClick={() => setField("paymentMethod", value)}
                        >
                          {label}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className={styles.actions}>
              <button
                type="button"
                className="btn btn-outline btn-pill"
                onClick={previousStep}
                disabled={stepIndex === 0 || submitting}
              >
                <ChevronLeft size={16} /> Back
              </button>

              {stepIndex < steps.length - 1 ? (
                <button
                  type="button"
                  className="btn btn-primary btn-pill"
                  onClick={nextStep}
                  disabled={submitting}
                >
                  Next <ChevronRight size={16} />
                </button>
              ) : (
                <button
                  type="button"
                  className="btn btn-primary btn-pill"
                  onClick={submitBooking}
                  disabled={submitting}
                >
                  {submitting ? "Submitting..." : "Submit Booking Request"}
                </button>
              )}
            </div>
          </SectionReveal>
        </div>
      </section>
    </>
  );
}

